package com.tidex.mobile.meshimport android.content.Contextclass AuthSessionStore(context: Context) {    private val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)    fun getCurrentUserId(): String? = prefs.getString(KEY_USER_ID, null)    fun saveCurrentUserId(userId: String) {        prefs.edit().putString(KEY_USER_ID, userId).apply()    }    companion object {        private const val PREFS_NAME = "tidex_auth_session"        private const val KEY_USER_ID = "current_user_id"    }}